28	// Windows ships npm/npx/firebase/flutter as .cmd shims; Bun.spawn won't resolve
29	// the bare name. node.exe is on PATH directly, so it stays as-is.
30	const IS_WIN = process.platform === "win32";
31	const bin = (name: string) => (IS_WIN ? `${name}.cmd` : name);
32	
33	const FIRESTORE_PORT = 8080;
34	const AUTH_PORT = 9099;
35	const FUNCTIONS_PORT = 5001;
36	const UI_PORT = 4000;
37	
