42	console.log(`[dev] emulator UI will be at http://127.0.0.1:${UI_PORT}`);
43	
44	// One-shot build so the emulator never loads stale lib/*.js. tsc is fast on
45	// this codebase (~1s) and avoids the "I edited a .ts but my callable didn't
46	// change" footgun.
47	console.log("[dev] building functions (tsc)???");
48	const buildOnce = Bun.spawn([bin("npm"), "run", "build"], {
