3	import 'package:flutter/material.dart';
4	import 'package:flutter_riverpod/flutter_riverpod.dart';
5	import 'package:go_router/go_router.dart';
6	
7	import '../features/admin/inventory_page.dart';
8	import '../features/admin/requests_page.dart';
9	import '../features/auth/login_page.dart';
10	import '../features/auth/register_page.dart';
11	import '../features/user/home_page.dart';
12	import '../features/user/profile_page.dart';
13	import '../features/user/queue_page.dart';
14	import 'auth/auth_providers.dart';
15	
16	const _publicRoutes = {'/login', '/register'};
17	
18	/// Single source of truth for navigation. Watched by [DroneAidApp].
19	final routerProvider = Provider<GoRouter>((ref) {
20	  return GoRouter(
21	    initialLocation: '/login',
22	    refreshListenable: _AuthListenable(ref),
23	    redirect: (context, state) {
24	      final auth = ref.read(authStateProvider);
25	      final profile = ref.read(userProfileProvider);
26	      final loc = state.matchedLocation;
27	      final isPublic = _publicRoutes.contains(loc);
28	
29	      // Still resolving cold-start auth ??? let splash render.
30	      if (auth.isLoading) return null;
31	
32	      final user = auth.valueOrNull;
33	      if (user == null) {
34	        return isPublic ? null : '/login';
35	      }
36	
37	      // Signed in but profile not yet loaded ??? keep on splash, redirect later.
38	      if (profile.isLoading) return isPublic ? null : null;
39	
40	      final role = profile.valueOrNull?.role ?? 'user';
41	      final landing = role == 'admin' ? '/admin/requests' : '/user/home';
42	
43	      if (isPublic) return landing;
44	      if (loc.startsWith('/admin') && role != 'admin') return '/user/home';
45	      return null;
46	    },
47	    routes: [
48	      GoRoute(path: '/login',    builder: (_, __) => const LoginPage()),
49	      GoRoute(path: '/register', builder: (_, __) => const RegisterPage()),
50	
51	      // User
52	      GoRoute(path: '/user/home',           builder: (_, __) => const UserHomePage()),
53	      GoRoute(path: '/user/queue',          builder: (_, __) => const QueuePage()),
54	      GoRoute(
55	        path: '/user/tracking/:flightId',
56	        builder: (_, state) =>
57	            _Placeholder('Tracking flight ${state.pathParameters['flightId']} (P-U-05)'),
58	      ),
59	      GoRoute(
60	        path: '/user/confirm/:reqId',
61	        builder: (_, state) =>
62	            _Placeholder('Confirm request ${state.pathParameters['reqId']} (P-U-06)'),
63	      ),
64	      GoRoute(path: '/user/history',        builder: (_, __) => const _Placeholder('History (P-U-07)')),
65	      GoRoute(path: '/user/notifications',  builder: (_, __) => const _Placeholder('Notifications (P-U-08)')),
66	      GoRoute(path: '/user/profile',        builder: (_, __) => const ProfilePage()),
